// ===============================
// 1) TELEFONE
// ===============================
const input = $input.first().json;
const body = input.body || {};

const rawPhone = String(body.Telefone || '');
let cleaned = rawPhone.replace(/\D/g, '');

if (cleaned.length === 11) {
  cleaned = '55' + cleaned;
} else if (cleaned.length === 13 && cleaned.startsWith('55')) {
  // ok
} else if (cleaned.length === 12 && !cleaned.startsWith('55')) {
  cleaned = '55' + cleaned;
} else {
  cleaned = '';
}

// ===============================
// 2) UF: Nome do estado -> Sigla
// ===============================
const estadoParaUF = {
  "ACRE": "AC",
  "ALAGOAS": "AL",
  "AMAPÁ": "AP",
  "AMAPA": "AP",
  "AMAZONAS": "AM",
  "BAHIA": "BA",
  "CEARÁ": "CE",
  "CEARA": "CE",
  "DISTRITO FEDERAL": "DF",
  "ESPÍRITO SANTO": "ES",
  "ESPIRITO SANTO": "ES",
  "GOIÁS": "GO",
  "GOIAS": "GO",
  "MARANHÃO": "MA",
  "MARANHAO": "MA",
  "MATO GROSSO": "MT",
  "MATO GROSSO DO SUL": "MS",
  "MINAS GERAIS": "MG",
  "PARÁ": "PA",
  "PARA": "PA",
  "PARAÍBA": "PB",
  "PARAIBA": "PB",
  "PARANÁ": "PR",
  "PARANA": "PR",
  "PERNAMBUCO": "PE",
  "PIAUÍ": "PI",
  "PIAUI": "PI",
  "RIO DE JANEIRO": "RJ",
  "RIO GRANDE DO NORTE": "RN",
  "RIO GRANDE DO SUL": "RS",
  "RONDÔNIA": "RO",
  "RONDONIA": "RO",
  "RORAIMA": "RR",
  "SANTA CATARINA": "SC",
  "SÃO PAULO": "SP",
  "SAO PAULO": "SP",
  "SERGIPE": "SE",
  "TOCANTINS": "TO"
};

// ✅ IDs REAIS do seu campo "UF do CRM" (enum)
const ufMap = {
  "AC": 6050,
  "AL": 6051,
  "AP": 6052,
  "AM": 6053,
  "BA": 6054,
  "CE": 6055,
  "DF": 6056,
  "ES": 6057,
  "GO": 6058,
  "MA": 6059,
  "MT": 6060,
  "MS": 6061,
  "MG": 6062,
  "PA": 6063,
  "PB": 6064,
  "PR": 6065,
  "PE": 6066,
  "PI": 6067,
  "RJ": 6068,
  "RN": 6069,
  "RS": 6070,
  "RO": 6071,
  "RR": 6072,
  "SC": 6073,
  "SP": 6074,
  "SE": 6075,
  "TO": 6076
};

// pega UF do CRM como veio (estado por extenso ou sigla)
const ufBruto = String(body["UF do CRM"] || "").trim();
const ufUpper = ufBruto.toUpperCase();

// se já veio "RJ", usa; se veio "Rio de Janeiro", converte pra "RJ"
const ufSigla = ufUpper.length === 2 ? ufUpper : (estadoParaUF[ufUpper] || "");
const UF_ID = ufSigla ? (ufMap[ufSigla] ?? null) : null;

// ===============================
// 3) PROFISSÃO: frase -> categoria
// ===============================
const profissionalMap = {
  "Médico": 2,
  "Medico": 2,
  "Fisioterapeuta": 3,
  "Enfermeiro": 4,
  "Nutricionista": 5,
  "Outro": 6
};

const profBruto = String(body.Profissional || "").trim();

// normaliza casos tipo "Sou Médico"
let profNorm = profBruto
  .replace(/^sou\s+/i, "")      // remove "Sou "
  .replace(/^eu\s+sou\s+/i, "") // remove "Eu sou "
  .trim();

// padroniza alguns sinônimos comuns
if (/medic/i.test(profNorm)) profNorm = "Médico";
if (/fisio/i.test(profNorm)) profNorm = "Fisioterapeuta";
if (/enferm/i.test(profNorm)) profNorm = "Enfermeiro";
if (/nutri/i.test(profNorm)) profNorm = "Nutricionista";

const Profissional_ID = profissionalMap[profNorm] ?? null;

// ===============================
// 4) RETORNO
// ===============================
return [{
  json: {
    telefoneFormatado: cleaned,
    ufTextoRecebido: ufBruto,
    ufSigla,
    UF_ID,
    profissaoTextoRecebido: profBruto,
    profNorm,
    Profissional_ID,
  }
}];

